import{c as t,Q as o,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Decoder — 2026-05-22","description":"","frontmatter":{"title":"The Decoder — 2026-05-22","date":"2026-05-22T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-22-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-22-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-22-the-decoder.md"};function n(i,e,h,c,l,d){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="🔓-the-decoder-—-2026-05-22" tabindex="-1">🔓 The Decoder — 2026-05-22 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-22" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-22&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="google-checks-websites-for-llms-txt-in-new-agentic-browsing-audit" tabindex="-1"><a href="https://the-decoder.com/google-tests-websites-for-llms-txt-and-agent-compatibility/" target="_blank" rel="noreferrer">Google checks websites for llms.txt in new agentic browsing audit</a> <a class="header-anchor" href="#google-checks-websites-for-llms-txt-in-new-agentic-browsing-audit" aria-label="Permalink to &quot;[Google checks websites for llms.txt in new agentic browsing audit](https://the-decoder.com/google-tests-websites-for-llms-txt-and-agent-compatibility/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-21</em></p><p>Google is testing how well websites handle AI agents through a new experimental category called &quot;Agentic Browsing&quot; in its Lighthouse analysis tool.</p><p>The article <a href="https://the-decoder.com/google-tests-websites-for-llms-txt-and-agent-compatibility/" target="_blank" rel="noreferrer">Google checks websites for llms.txt in new agentic browsing audit</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="the-first-ai-proof-worthy-of-math-s-top-journal-landed-and-it-won-t-be-the-last" tabindex="-1"><a href="https://the-decoder.com/openai-shifts-the-boundary-of-automated-reasoning-with-a-milestone-in-ai-mathematics-that-experts-are-now-unpacking/" target="_blank" rel="noreferrer">The first AI proof worthy of math&#39;s top journal landed and it won&#39;t be the last</a> <a class="header-anchor" href="#the-first-ai-proof-worthy-of-math-s-top-journal-landed-and-it-won-t-be-the-last" aria-label="Permalink to &quot;[The first AI proof worthy of math&#39;s top journal landed and it won&#39;t be the last](https://the-decoder.com/openai-shifts-the-boundary-of-automated-reasoning-with-a-milestone-in-ai-mathematics-that-experts-are-now-unpacking/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-21</em></p><p>A reasoning model from OpenAI has disproved a conjecture by mathematician Paul Erdős on unit-distance geometry that stood open since 1946 - using tools from algebraic number theory that experts never expected in this context. Fields Medalist Tim Gowers calls the result &quot;a milestone in AI mathematics&quot; and warns: &quot;We have still probably entered an era where it will become very difficult for humans to compete with AI at solving mathematical problems.&quot;</p><p>The article <a href="https://the-decoder.com/openai-shifts-the-boundary-of-automated-reasoning-with-a-milestone-in-ai-mathematics-that-experts-are-now-unpacking/" target="_blank" rel="noreferrer">The first AI proof worthy of math&#39;s top journal landed and it won&#39;t be the last</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="us-cyber-command-races-to-deploy-ai-on-top-secret-networks" tabindex="-1"><a href="https://the-decoder.com/us-cyber-command-races-to-deploy-ai-on-top-secret-networks/" target="_blank" rel="noreferrer">US Cyber Command races to deploy AI on top-secret networks</a> <a class="header-anchor" href="#us-cyber-command-races-to-deploy-ai-on-top-secret-networks" aria-label="Permalink to &quot;[US Cyber Command races to deploy AI on top-secret networks](https://the-decoder.com/us-cyber-command-races-to-deploy-ai-on-top-secret-networks/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-21</em></p><p>US Cyber Command has launched a task force to run AI models from OpenAI, Google, and others on the most classified Pentagon and NSA networks. The trigger: AI systems like Anthropic&#39;s Claude Mythos can find security vulnerabilities faster than the best human hackers - and according to Anthropic, comparable tools could be widely available within six to 24 months.</p><p>The article <a href="https://the-decoder.com/us-cyber-command-races-to-deploy-ai-on-top-secret-networks/" target="_blank" rel="noreferrer">US Cyber Command races to deploy AI on top-secret networks</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="cohere-open-sources-its-strongest-model-yet" tabindex="-1"><a href="https://the-decoder.com/cohere-open-sources-its-strongest-model-yet/" target="_blank" rel="noreferrer">Cohere open-sources its strongest model yet</a> <a class="header-anchor" href="#cohere-open-sources-its-strongest-model-yet" aria-label="Permalink to &quot;[Cohere open-sources its strongest model yet](https://the-decoder.com/cohere-open-sources-its-strongest-model-yet/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-21</em></p><p>The Canadian AI company Cohere is releasing its most powerful language model to date, Command A+, as open source under an Apache 2.0 license.</p><p>The article <a href="https://the-decoder.com/cohere-open-sources-its-strongest-model-yet/" target="_blank" rel="noreferrer">Cohere open-sources its strongest model yet</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-is-about-to-become-the-first-profitable-ai-lab" tabindex="-1"><a href="https://the-decoder.com/anthropic-is-about-to-become-the-first-profitable-ai-lab/" target="_blank" rel="noreferrer">Anthropic is about to become the first profitable AI lab</a> <a class="header-anchor" href="#anthropic-is-about-to-become-the-first-profitable-ai-lab" aria-label="Permalink to &quot;[Anthropic is about to become the first profitable AI lab](https://the-decoder.com/anthropic-is-about-to-become-the-first-profitable-ai-lab/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-21</em></p><p>Anthropic is approaching its first profitable quarter, the Wall Street Journal reports - with a projected operating profit of $559 million on $10.9 billion in Q2 revenue. Just last summer, the company didn&#39;t expect to turn a profit before 2028. The main drivers are coding tools and agentic Claude usage, which at times pushed demand beyond available compute capacity.</p><p>The article <a href="https://the-decoder.com/anthropic-is-about-to-become-the-first-profitable-ai-lab/" target="_blank" rel="noreferrer">Anthropic is about to become the first profitable AI lab</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const f=t(s,[["render",n]]);export{m as __pageData,f as default};
